window.__QUIZ_DATA__=[{"id":"theory>Geography>2018>THEORY 1>1>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1: 50,000 and answer this question. (Attach the topographical map extract to your answer booklet).       On the attached topographical map extract, mark and name this feature using the Letters in the bracket;    - ridge (RG)  - col (CL)  - confluence (CF)  - spur (SP)  - isolated hill (IH)    -  -  -","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>1>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1: 50,000 and answer this question. (Attach the topographical map extract to your answer booklet).       Shade an area above 950 ft in the north western part of the map.","images":["data:image/png;base64,"],"marking_scheme":"map","marks":"2","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>1>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1: 50,000 and answer this question. (Attach the topographical map extract to your answer booklet).       In your answer booklet, calculate the gradient along the line between points A and B on the map.    (Leaving the answer in fraction q/p)","images":["data:image/png;base64,"],"marking_scheme":"Gradient=Vertical Interval (VI)Horizontal Equivalent (HE)  VI = (1100 - 850)ft = 250ft  1 inch = 2.54cm \u2248 2.50cm  250ft \u00d7 2.54cm  = 12.5cm \u00b1 0.1  Scale of map = 2cm is to 1km or 1:50,000  \u223412..52=6.25kmor12.5\u00d750,000=625,000cm  Gradient=250\u00d712\u00d72.546.25\u00d71000,000=7,620625,000=182or1in82","marks":"4","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>1>d","subject":"Geography","year":"2018","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Study the map extract provided on a scale of 1: 50,000 and answer this question. (Attach the topographical map extract to your answer booklet).       Describe two drainage characteristics of the River Tain.","images":["data:image/png;base64,"],"marking_scheme":"-      the major or largest river in the mapped area  -      has many tributaries  -      drainage pattern is dendritic  -      it flows from northwest to the centre and then eastwards  -      it is in its middle course  -      it flows through U-shaped valley  -      the width of the river is between 10-100ft  -      meanders are found in the north-west of the map.  -      the northern boundary is Tain forest reserve.  -      the slope of the river bed is gentle","marks":"4","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>2>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The Popuation distribution in the regions of Country M in the yea 2011 is represented in the table below. Use the data to answer this question:  REGIONPOPULATIONA100,000B380,000C160,000D220,000      Using the map and a scale of one dot to represent 20,000 persons, produce a dot map for Country M.","images":["data:image/png;base64,"],"marking_scheme":"Calculations on dots   RegionA=100,00020,000=5dots   RegionB=380,00020,000=19dots   RegionC=160,00020,000=11dots     Plotting of dots   Region A: 5 dots   Region B: 19 dots   Region C: 8 dots   Region D: 11 dots","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>2>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The Popuation distribution in the regions of Country M in the yea 2011 is represented in the table below. Use the data to answer this question:  REGIONPOPULATIONA100,000B380,000C160,000D220,000  On the dot map produced in 2 (a), suggest a suitable title","images":[],"marking_scheme":"Sot map showing distribution of population of the regions of country M in the year 2011.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>2>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The Popuation distribution in the regions of Country M in the yea 2011 is represented in the table below. Use the data to answer this question:  REGIONPOPULATIONA100,000B380,000C160,000D220,000  State two advantages of dot maps.","images":[],"marking_scheme":"- It is easy to interpret by counting the dots   - It gives good visual impression   - It can be used to represent a wide range of items   - It gives good visual impression.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>3>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"With the aid of annotated diagrams, explain the characteristics and mode of formation of this:    gorges;","images":[],"marking_scheme":"Characteristics and mode of formation of Gorges   - Gorges are elongated   - Gorges are steep sided   - Gorges favours the construction of dams   - Gorges are deep narrow river valley   - Gorges can be found in limestone regions  - Gorges are found along rejuvenated areas   - Gorges are very common in the upper course of rivers   - Gorges are usually V-shaped      Mode of Formation   - Formed where rivers cut deeply along the lines of weakness vertically   - Formed where waterfall retreats upstream   - Formed mostly in the upper course of a river   - Could be formed where a river crosses a limestone region","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>3>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"With the aid of annotated diagrams, explain the characteristics and mode of formation of this:  seif dunes.","images":[],"marking_scheme":"Characteristics of Seif-dunes   - Self-dunes are long and narrow ridges   - They are found in arid regions   - Seif-dunes lie parallel to the direction of the prevailing wind   - They could be over 100 km in length   - Their crests are characterised by peaks and saddles   - They could be up to 60 metres in height.      Mode of formation   Seif-dunes are formed in desert areas, they are formed due to wind deposition. Sand dunes are deposited parallel to the prevailing wind, wind blows to clear the corridors between the dunes of sand; eddies blow towards the side of the corridors. This results in long parallel mounds of sand called the seif dunes.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>4>a>i","subject":"Geography","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"List three landforms found in limestone regions","images":[],"marking_scheme":"- Stalactite   - Stalagmite   - Doline   - Urala   - Clint   - Dry valley   - Grike (Gryke)  - Chalk cuesta","marks":"5","difficulty":"1"},{"id":"theory>Geography>2018>THEORY 1>4>a>ii","subject":"Geography","year":"2018","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Draw a well labelled diagram to show the underground features of a limestone region.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>4>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Outline three ways by which limestone is beneficial to man.","images":[],"marking_scheme":"- Limestone is used as raw materials in cement industrial  - Limestone can be used in the manufacturing of glass   - Limestone is used to reduce soil fertility   - Limestone serves as a source of underground water   - It serves as a tourist centre","marks":"5","difficulty":"1"},{"id":"theory>Geography>2018>THEORY 1>5>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"With the aid of a diagram, explain eclipse of the moon.","images":["data:image/png;base64,"],"marking_scheme":"Eclipse of the Moon     The eclipse of the moon also called the Lumer eclipse occurs when the earth comes between the sun and the moon; hence the earth blocks rays of the sun from reaching the moon. For this reason, the shadow (darkness) of the earth is cast on the moon. This unusual darkness is called eclipse.     Note that total coverage of the moon leads total eclipse while the partial coverage of the moon leads to partial eclipse.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>5>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"State three characteristics of Great Circles.","images":[],"marking_scheme":"- The centre of the Great Circles is also the centre of earth   - The Equator is the only latitude that is a Great Circle   - Great Circles are imaginary circular lines drawn on maps or globes  - Great circles run in all direction   - Great circles are equal in length.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>5>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Outline three uses of Great Circles.","images":[],"marking_scheme":"- The Great circle is used in ship navigation   - The Great circle is used in determining the approximate distance between two points on the earth's surface.  - The Great circle is used for locating places on the earth's surface.  - It is used in determining directions","marks":"5","difficulty":"1"},{"id":"theory>Geography>2018>THEORY 1>6","subject":"Geography","year":"2018","type":"Theory","sub_label":"6","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Contrast the characteristics of Equatorial climate with the Tundra climate.","images":[],"marking_scheme":"- Equitorial climate is located near the Equator while the Tundra climate is located near the poles   - Equatorial climate has high temperature all year round while Tundra has low temperature all year round  - Equitorial climate has double maximum rainfall while Tundra has single maximum rainfall   - The sun rays are vertical in the Equatorial areas while they are inclined in Tundra regions   - Equatorial mean temperature is as high as 27oc while Tundra temperature is as low as -29oc.   - Equitorial climate experiences a small annual range of temperature of about 1o to 3o while the Tundra has a high annual range of temperature of 40oc - 50oc.   - Rainfall occurs in Equitorial climatic area while snow occurs in Tundra climatic areas.","marks":"20","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 1>7>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With appropriate diagrams, outline three conditions under which this feature can be formed;    river capture;","images":[],"marking_scheme":"- There must be two parallel consequent rivers   - The consequent rivers must be separated by water shed   - One of the rivers must have more erosive power than the other.  - The valley of the more powerful river must be deeper than the other.  - The powerful river should have steeper slope or gradient.","marks":"12","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>7>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With appropriate diagrams, outline three conditions under which this feature can be formed;  waterfall","images":[],"marking_scheme":"- There must be a resistant rock   - The resistant rock must lie across the river valley   - The river plunge over the resistant rock to form a waterfall","marks":"8","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>8>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Write a geographical account of flooding in urban areas under this heading;    four causes","images":[],"marking_scheme":"- Volcanic eruption   - Dumping of refuse into drains   - Excessive rainfall   - Poor construction of drainage system   - Non - enforcement of environmental laws   - Inadequate urban planning","marks":"8","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>8>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Write a geographical account of flooding in urban areas under this heading;  three effects","images":[],"marking_scheme":"- Loss of lives and properties   - Difficulty in movement of people, goods and services   - Interruption of social and economic activities   - Environmental pollution   - Deposition of Silt and garbage.   - Facilitates the speed of waterborne diseases.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 1>8>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Write a geographical account of flooding in urban areas under this heading;  four measures that can be used to control the flooding","images":[],"marking_scheme":"- Public enlightenment and enforcement of legislation against indiscriminate waste disposal   - Construction of wider culverts and drains   - Provision of more refuse bins  - Environmental education in schools   - Establishment of disaster management agencies","marks":"5","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 2>1>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight three characteristics of manufacturing industries in Tropical Africa","images":[],"marking_scheme":"- They are labour intensive   - They are majorly light industries   - They depend on imported machineries   - They are majorly import substitutes","marks":"8","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>1>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"State three ways by which manufacturing industries contribute to the economic development of Tropical Africa","images":[],"marking_scheme":"- Manpower development   - Diversification of the economy   - Stimulation of other sectors   - Employment opportunities   - Increase in Cross National Product (GNP)","marks":"7","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>1>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline four problems facing industrial developments in Tropical Africa","images":[],"marking_scheme":"- Poor quality of industrial labour   - Competition from foreign products   - High degree of foreign dependence   - Low purchasing power of the populace   - Inadequate capital","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>2>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline four ways in which urban settlements differ from one another","images":[],"marking_scheme":"- Size   - Favorable Climate  - Site (Location)   - Mineral resources   - Medical facilities   - Rich fertile soil","marks":"8","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>2>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Outline three factors that have contributed to the high population density in Japan","images":[],"marking_scheme":"- large markets   - Accessibility   - Immigration   - Industrialization   - Improved medical facilities","marks":"7","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>2>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"State three problems resulting from high population density in Japan","images":[],"marking_scheme":"- Inadequate housing   - Traffic congestion   - Environmental pollution   - Pressure on social amenities   - Insufficient food","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>3>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Identify four ocean routes used in the world trade.","images":[],"marking_scheme":"- The Panama Canal Route  - The North Pacific Route  - Trans-pacific Route  - The South-Africa or Cape Route","marks":"8","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 2>3>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"In what four ways has water transportation contributed to economic developments?","images":[],"marking_scheme":"-  National and International trade   -  Development of Tourism   - Employment   - Opening up new lands and areas   - Access to natural resources","marks":"7","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>3>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Outline four ways of improving transportation on inland waterways","images":[],"marking_scheme":"- Ship should be equipped with refrigerated holds   - Construction of canals to by-pass water falls and cataracts   - Medical facilities on board should be improved   - Loans should be granted to construct and maintain sea ports","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>4>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Describe three characteristics of subsistence of agriculture in Nigeria","images":[],"marking_scheme":"- Subsistence agriculture is mostly practiced by peasant farmers   - Subsistence agriculture involves small portion of land   - It involves the use of crude farm implements like cutlass and hoe   - It involves small capital to start up   - Subsistence agriculture is practised to provide for the basic needs of the family   - It usually involves the use of family labour.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>4>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline four advantages of subsistence agriculture","images":[],"marking_scheme":"- Cost of labour is low   - Very little capital requirement   - It requires a small area of land   - It does not require any special marketing strategies","marks":"7","difficulty":"1"},{"id":"theory>Geography>2018>THEORY 2>4>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight three disadvantages of subsistence agriculture","images":[],"marking_scheme":"- Crude tools are not efficient   - Inadequate capital for investment   - There is no adequate measure to control pests and diseases   - The farmer is usually an illiterate.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2018>THEORY 2>5>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Draw a sketch map of Nigeria  On the map, locate and name one area important for the manufacturing of:  i. Cement;  ii. Cocoa products;  iii. Flour","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 2>5>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Highlight three benefits of large-scale manufacturing industries in Nigeria","images":[],"marking_scheme":"- Employment opportunities   - Increase in gross National Product (GNP)  - Man power development   - Control of inflation due to mass production   - Stimulation of other sectors","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>5>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline three advantages which large-scales manufacturing industries have over small-scale manufacturing industries","images":[],"marking_scheme":"- They make use of higher-level personel in their management   - They have make use of higher level technology   - They have more access to credit facilities   - They sell out their products at cheaper prices","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>6>a","subject":"Geography","year":"2018","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Draw a sketch map of Nigeria   On the map, show and name one area each where the following minerals are mind:  i. Coal;  ii. Crude oil;  iii. Limestone","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2018>THEORY 2>6>b","subject":"Geography","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe the process of mining coal in Nigeria","images":[],"marking_scheme":"- A tunnel is cut into the coal stream   - Explosives are then used to dig out the tunnel to the surface or   - A light rail car hauls the coal from the tunnel to the surface or into lorries from where it is exported to other countries or utilized locally","marks":"5","difficulty":"2"},{"id":"theory>Geography>2018>THEORY 2>6>c","subject":"Geography","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Identify four problems affecting the mining industry in Nigeria.","images":[],"marking_scheme":"- Environmental pollution   - Inadequate capital for the exploitation of minerals   - Lack of inadequate trained personnel in mining and exploitation of the minerals  - Outdated topographical maps are used   - Poor transport network","marks":"5","difficulty":"2"}];